import numpy as np

def predict(frame, action):
    out = frame.copy()
    H, W = out.shape
    BG = 5
    OBJ = 10
    mask = (frame == OBJ)

    # connected components (4-conn) of object cells -> each is a 5x5 bar
    seen = np.zeros_like(mask, dtype=bool)
    comps = []
    for (r0, c0) in zip(*np.where(mask)):
        if seen[r0, c0]:
            continue
        stack = [(r0, c0)]
        seen[r0, c0] = True
        comp = []
        while stack:
            r, c = stack.pop()
            comp.append((r, c))
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < H and 0 <= nc < W and mask[nr, nc] and not seen[nr, nc]:
                    seen[nr, nc] = True
                    stack.append((nr, nc))
        comps.append(comp)

    old_cells = set()
    new_cells = set()
    for comp in comps:
        center = sum(c for _, c in comp) / len(comp)
        if action == 1:
            dr, dc = -5, 0          # up
        elif action == 2:
            dr, dc = 5, 0           # down
        elif action == 3:
            dr, dc = 0, (-5 if center < 31.5 else 5)   # spread
        elif action == 4:
            dr, dc = 0, (5 if center < 31.5 else -5)   # contract
        else:
            dr, dc = 0, 0           # no-op / unknown
        old_cells.update(comp)
        for (r, c) in comp:
            nr, nc = r + dr, c + dc
            if 0 <= nr < H and 0 <= nc < W:
                new_cells.add((nr, nc))

    for (r, c) in old_cells - new_cells:
        out[r, c] = BG
    for (r, c) in new_cells:
        out[r, c] = OBJ

    return out
